// Bundle research inputs into a single context blob for the LLM.
// Each input item has the previous node's body in $input.first().json or .data.

const rss = $('Fetch Disney Parks Blog RSS').first()?.json?.data ?? $('Fetch Disney Parks Blog RSS').first()?.json ?? '';
const parks = $('Fetch themeparks.wiki destinations').first()?.json ?? {};

// Today's date in Eastern Time (YYYY-MM-DD)
const now = new Date();
const etDate = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'America/New_York',
  year: 'numeric', month: '2-digit', day: '2-digit'
}).format(now);

const slug = `disney-park-news-${etDate}`;
const niceDate = new Date(etDate + 'T00:00:00Z').toLocaleDateString('en-US', {
  timeZone: 'UTC', month: 'long', day: 'numeric', year: 'numeric'
});

return [{
  json: {
    today: etDate,
    slug,
    title: `Disney Park News — ${niceDate}`,
    rss: typeof rss === 'string' ? rss.slice(0, 30000) : JSON.stringify(rss).slice(0, 30000),
    parks: JSON.stringify(parks).slice(0, 5000)
  }
}];

