// Extract Claude's text output, parse JSON, validate the shape.
// Throws if anything is malformed — n8n surfaces it in the run history
// and the workflow stops (no broken file commits).

const resp = $input.first().json;
const text = resp?.content?.[0]?.text ?? '';
if (!text) throw new Error('Claude returned no text content');

// Strip any accidental markdown fence
const jsonStr = text.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/, '').trim();

let post;
try {
  post = JSON.parse(jsonStr);
} catch (e) {
  throw new Error('Claude output is not valid JSON: ' + e.message + '\n---\n' + jsonStr.slice(0, 500));
}

// Schema sanity checks
const required = ['title', 'slug', 'date', 'teaser'];
for (const k of required) {
  if (!post[k] || typeof post[k] !== 'string') {
    throw new Error(`Missing required field: ${k}`);
  }
}
if (!/^disney-park-news-\d{4}-\d{2}-\d{2}$/.test(post.slug)) {
  throw new Error(`Slug doesn't match disney-park-news-YYYY-MM-DD: ${post.slug}`);
}
if (post.teaser.length > 220) {
  throw new Error(`Teaser too long (${post.teaser.length} chars)`);
}

const VALID_PARKS = ['magic-kingdom','epcot','hollywood-studios','animal-kingdom','disneyland','california-adventure'];
for (const sec of Object.values(post.sections ?? {})) {
  if (!Array.isArray(sec)) continue;
  for (const item of sec) {
    if (item.parkSlug && !VALID_PARKS.includes(item.parkSlug)) {
      throw new Error(`Invalid parkSlug: ${item.parkSlug}`);
    }
  }
}
for (const ride of (post.rightNow?.rides ?? [])) {
  if (ride.parkSlug && !VALID_PARKS.includes(ride.parkSlug)) {
    throw new Error(`Invalid rightNow parkSlug: ${ride.parkSlug}`);
  }
}

// Force updatedAt to now
post.updatedAt = new Date().toISOString();

return [{
  json: {
    slug: post.slug,
    post,
    fileContent: JSON.stringify(post, null, 2)
  }
}];

